mapper.select:
SELECT stat_month AS timeDim, SUM(revenue_amount) AS revenueAmount, SUM(floating_rent_amount) AS floatingRentAmount, ROUND(AVG(avg_revenue_per_sqm), 2) AS avgRevenuePerSqm, SUM(passenger_flow) AS passengerFlow, SUM(avg_daily_passenger) AS avgDailyPassenger, SUM(change_count) AS changeCount, SUM(change_rent_impact) AS changeRentImpact, SUM(expiring_contracts) AS expiringContracts, SUM(terminated_contracts) AS terminatedContracts FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0 AND format_type = ''
AND format_type = #{formatType}
GROUP BY stat_month ORDER BY stat_month

SELECT stat_month AS timeDim, project_id AS projectId, format_type AS formatType, SUM(revenue_amount) AS revenueAmount, SUM(floating_rent_amount) AS floatingRentAmount, ROUND(AVG(avg_revenue_per_sqm), 2) AS avgRevenuePerSqm FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0
AND format_type = #{formatType}
GROUP BY stat_month, project_id, format_type ORDER BY stat_month, project_id

SELECT stat_month AS timeDim, project_id AS projectId, format_type AS formatType, SUM(change_count) AS changeCount, SUM(change_rent_impact) AS changeRentImpact FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0
AND format_type = #{formatType}
GROUP BY stat_month, project_id, format_type ORDER BY stat_month, project_id

SELECT stat_month AS timeDim, project_id AS projectId, format_type AS formatType, SUM(change_rent_impact) AS changeRentImpact, SUM(change_count) AS changeCount, CASE WHEN SUM(change_count) > 0 THEN ROUND(SUM(change_rent_impact) / SUM(change_count), 2) ELSE 0 END AS avgChangeImpact FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0
AND format_type = #{formatType}
GROUP BY stat_month, project_id, format_type ORDER BY stat_month, project_id

SELECT stat_month AS timeDim, project_id AS projectId, format_type AS formatType, SUM(terminated_contracts) AS terminatedContracts FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0
AND format_type = #{formatType}
GROUP BY stat_month, project_id, format_type ORDER BY stat_month, project_id

SELECT stat_month AS timeDim, project_id AS projectId, format_type AS formatType, SUM(floating_rent_amount) AS floatingRentAmount FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0
AND format_type = #{formatType}
GROUP BY stat_month, project_id, format_type ORDER BY stat_month, project_id

SELECT stat_month AS timeDim, project_id AS projectId, format_type AS formatType, SUM(change_count) AS changeCount, SUM(change_rent_impact) AS changeRentImpact, SUM(terminated_contracts) AS terminatedContracts, SUM(expiring_contracts) AS expiringContracts FROM rpt_operation_monthly WHERE is_deleted = 0 AND building_id = 0
AND format_type = #{formatType}
GROUP BY stat_month, project_id, format_type ORDER BY stat_month, project_id
